import{_ as e,o as a,c as i,aw as s}from"./chunks/framework.CrejmIte.js";const t=JSON.parse('{"title":"ADR 023: Proposer Key Rotation via Height-Based Schedule","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ADR 023: Proposer Key Rotation via Height-Based Schedule | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"adr/adr-023-proposer-key-rotation.md","filePath":"adr/adr-023-proposer-key-rotation.md","lastUpdated":1776951550000}');const o=e({name:"adr/adr-023-proposer-key-rotation.md"},[["render",function(e,t,o,n,r,l){return a(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="adr-023-proposer-key-rotation-via-height-based-schedule" tabindex="-1">ADR 023: Proposer Key Rotation via Height-Based Schedule <a class="header-anchor" href="#adr-023-proposer-key-rotation-via-height-based-schedule" aria-label="Permalink to &quot;ADR 023: Proposer Key Rotation via Height-Based Schedule&quot;">​</a></h1><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><ul><li>2026-04-23: Implemented proposer key rotation through a height-indexed proposer schedule</li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ev-node historically treated the proposer as a single static identity embedded in genesis via <code>proposer_address</code>. That assumption leaked into block production, DA submission, and sync validation. As a result, rotating a compromised or operationally obsolete proposer key required out-of-band coordination and effectively behaved like a manual re-genesis from the point of view of node operators.</p><p>This was suboptimal for three reasons:</p><ol><li>It made proposer rotation operationally risky and easy to get wrong.</li><li>Fresh nodes syncing from genesis had no protocol-visible record of when the proposer changed.</li><li>Validation only pinned the proposer address, not the scheduled public key that should be producing blocks.</li></ol><h2 id="alternative-approaches" tabindex="-1">Alternative Approaches <a class="header-anchor" href="#alternative-approaches" aria-label="Permalink to &quot;Alternative Approaches&quot;">​</a></h2><h3 id="_1-manual-key-swap-only" tabindex="-1">1. Manual key swap only <a class="header-anchor" href="#_1-manual-key-swap-only" aria-label="Permalink to &quot;1. Manual key swap only&quot;">​</a></h3><p>Operators can stop the sequencer, swap the local signer, redistribute config, and restart nodes. This is insufficient because the chain itself does not encode when the proposer changed, so historical sync and validation become ambiguous.</p><h3 id="_2-re-issue-a-new-genesis-on-each-rotation" tabindex="-1">2. Re-issue a new genesis on each rotation <a class="header-anchor" href="#_2-re-issue-a-new-genesis-on-each-rotation" aria-label="Permalink to &quot;2. Re-issue a new genesis on each rotation&quot;">​</a></h3><p>This treats every proposer rotation like a chain restart. It is operationally heavy, conflates upgrades with rotations, and breaks continuity for nodes syncing historical data.</p><h3 id="_3-height-indexed-proposer-schedule-in-genesis-chosen" tabindex="-1">3. Height-indexed proposer schedule in genesis (Chosen) <a class="header-anchor" href="#_3-height-indexed-proposer-schedule-in-genesis-chosen" aria-label="Permalink to &quot;3. Height-indexed proposer schedule in genesis (Chosen)&quot;">​</a></h3><p>Record proposer changes as an ordered schedule indexed by activation height. This preserves chain continuity while making rotation rules explicit and replayable from genesis.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>ev-node now supports proposer rotation through a <code>proposer_schedule</code> field in genesis.</p><p>Each entry declares:</p><ul><li><code>start_height</code></li><li><code>address</code></li><li><code>pub_key</code></li></ul><p>The active proposer for block height <code>h</code> is the last entry whose <code>start_height &lt;= h</code>.</p><p>The legacy <code>proposer_address</code> field remains for backward compatibility. When no explicit schedule is present, ev-node derives an implicit single-entry schedule beginning at <code>initial_height</code>.</p><p>When an explicit schedule is present:</p><ul><li>the first entry must start at <code>initial_height</code></li><li>entries must be strictly increasing by <code>start_height</code></li><li>each entry&#39;s <code>address</code> must match the configured <code>pub_key</code></li><li><code>proposer_address</code>, when present, must match the first schedule entry</li></ul><h2 id="detailed-design" tabindex="-1">Detailed Design <a class="header-anchor" href="#detailed-design" aria-label="Permalink to &quot;Detailed Design&quot;">​</a></h2><h3 id="data-model" tabindex="-1">Data model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data model&quot;">​</a></h3><p>Genesis gains:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;proposer_schedule&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;start_height&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;address&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;pub_key&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;start_height&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1250000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;address&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;pub_key&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>The existing <code>proposer_address</code> field is retained as a compatibility field and is normalized to the first scheduled proposer when a schedule is present.</p><h3 id="validation-rules" tabindex="-1">Validation rules <a class="header-anchor" href="#validation-rules" aria-label="Permalink to &quot;Validation rules&quot;">​</a></h3><p>The proposer schedule is now consulted in all proposer-sensitive paths:</p><ol><li>executor startup accepts any signer that appears somewhere in the schedule</li><li>block creation resolves the proposer for the exact height being produced</li><li>DA submission validates the configured signer against the scheduled proposer for each signed data height</li><li>sync validation validates incoming headers and signed data against the scheduled proposer for their heights</li></ol><p>This makes proposer rotation protocol-visible for both live nodes and nodes syncing historical data.</p><h3 id="operational-procedure" tabindex="-1">Operational procedure <a class="header-anchor" href="#operational-procedure" aria-label="Permalink to &quot;Operational procedure&quot;">​</a></h3><p>For a planned rotation:</p><ol><li>Choose activation height <code>H</code></li><li>Add a new <code>proposer_schedule</code> entry with <code>start_height = H</code></li><li>Distribute the updated genesis/config to node operators</li><li>Upgrade follower/full nodes before activation</li><li>Stop the old sequencer before <code>H</code></li><li>Start the new sequencer with the replacement key at or after <code>H</code></li></ol><p>The old proposer remains valid for heights <code>&lt; H</code>, and the new proposer becomes valid at heights <code>&gt;= H</code>.</p><h3 id="security-considerations" tabindex="-1">Security considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security considerations&quot;">​</a></h3><p>This design improves safety over address-only pinning by allowing validation against the scheduled public key. It does not solve emergency rotation authorization by itself; a future design can add a separate upgrade authority or rotation certificate flow if the network needs signer replacement without prior static scheduling.</p><h3 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h3><p>Coverage includes:</p><ul><li>genesis schedule validation and height resolution</li><li>sync acceptance of scheduled proposer rotation</li><li>DA submission using a rotated proposer key at the configured height</li><li>executor block creation using the proposer scheduled for the produced height</li></ul><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Implemented</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>proposer rotation is now part of the chain configuration rather than an operator convention</li><li>fresh nodes can validate historical proposer changes from genesis</li><li>sync and DA validation can pin scheduled public keys, not just addresses</li><li>routine key rotation no longer requires a chain restart</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>proposer schedule changes are consensus-visible and require coordinated rollout</li><li>operators must distribute updated genesis/config before activation height</li><li>emergency rotation still requires preplanned scheduling or a later authority-based mechanism</li></ul><h3 id="neutral" tabindex="-1">Neutral <a class="header-anchor" href="#neutral" aria-label="Permalink to &quot;Neutral&quot;">​</a></h3><ul><li>legacy single-proposer deployments continue to work without defining <code>proposer_schedule</code></li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="./../../pkg/genesis/genesis.go">pkg/genesis/genesis.go</a></li><li><a href="./../../pkg/genesis/proposer_schedule.go">pkg/genesis/proposer_schedule.go</a></li><li><a href="./../../block/internal/executing/executor.go">block/internal/executing/executor.go</a></li><li><a href="./../../block/internal/syncing/assert.go">block/internal/syncing/assert.go</a></li></ul>',51)])])}]]);export{t as __pageData,o as default};
